describe('POST /auth/reset-password', () => {
  it('resets password with valid token', async () => {
    const user = await createUser({ email: 'test@example.com', password: 'old' });
    const resetToken = await generateResetToken(user.id);
    await request(app)
      .post('/auth/reset-password')
      .send({ email: 'test@example.com', resetToken, newPassword: 'new123' })
      .expect(200);
    // Verify can login with new password
    await request(app)
      .post('/auth/login')
      .send({ email: 'test@example.com', password: 'new123' })
      .expect(200);
  });
});

it('rejects expired reset token', async () => {
  const user = await createUser({ email: 'test@example.com', password: 'old' });
  const expiredToken = await generateResetToken(user.id, { expiresIn: -1000 });
  await request(app)
    .post('/auth/reset-password')
    .send({ email: 'test@example.com', resetToken: expiredToken, newPassword: 'new' })
    .expect(401);
});

it('prevents token reuse', async () => {
  const user = await createUser({ email: 'test@example.com', password: 'old' });
  const resetToken = await generateResetToken(user.id);
  // First reset succeeds
  await request(app)
    .post('/auth/reset-password')
    .send({ email: 'test@example.com', resetToken, newPassword: 'new1' })
    .expect(200);
  // Second reset with same token fails
  await request(app)
    .post('/auth/reset-password')
    .send({ email: 'test@example.com', resetToken, newPassword: 'new2' })
    .expect(401);
});
